/**
 * AURA ALPHA -- Client-Side Compute Web Worker
 * =============================================
 * Runs in the background when a user is signed in. Fetches computation
 * jobs from the server, processes them locally using the browser's CPU,
 * and submits results back.
 *
 * Security: users ONLY process their OWN data (enforced by server-side
 * user_id filtering on every API call).
 *
 * Features:
 *   - Battery-aware: reduces polling when on battery
 *   - CPU-aware: respects navigator.hardwareConcurrency
 *   - Graceful shutdown: stops cleanly on 'stop' message
 *   - Error resilient: reports failures, continues processing
 *
 * Messages IN:
 *   { type: 'start', payload: { token, apiBase } }
 *   { type: 'stop' }
 *   { type: 'status' }
 *
 * Messages OUT:
 *   { type: 'status', data: { running, jobsCompleted, cpuTimeMs, ... } }
 *   { type: 'job_completed', data: { jobId, jobType, cpuTimeMs } }
 *   { type: 'job_failed', data: { jobId, error } }
 *   { type: 'error', data: { message } }
 *   { type: 'idle', data: { nextPollMs } }
 */

// ── Worker State ─────────────────────────────────────────────────────────

let running = false;
let token = '';
let apiBase = '/api';
let loopHandle = null;

// Stats
let jobsCompleted = 0;
let jobsFailed = 0;
let totalCpuTimeMs = 0;
let lastJobAt = null;

// Tuning
const BASE_POLL_MS = 5000;      // 5s between work-package polls when active
const IDLE_POLL_MS = 15000;     // 15s when no jobs available
const BATTERY_POLL_MS = 30000;  // 30s when on battery
const MAX_CONCURRENT = Math.max(1, Math.min((typeof navigator !== 'undefined' && navigator.hardwareConcurrency) || 4, 8));

// ── Message Handler ──────────────────────────────────────────────────────

self.onmessage = function (e) {
  const { type, payload } = e.data;

  switch (type) {
    case 'start':
      if (!running) {
        token = payload.token;
        apiBase = payload.apiBase || '/api';
        startComputeLoop();
      }
      break;

    case 'stop':
      stopComputeLoop();
      break;

    case 'status':
      self.postMessage({ type: 'status', data: getStatus() });
      break;

    default:
      break;
  }
};

// ── Status ───────────────────────────────────────────────────────────────

function getStatus() {
  return {
    running,
    jobsCompleted,
    jobsFailed,
    totalCpuTimeMs: Math.round(totalCpuTimeMs),
    lastJobAt,
    maxConcurrent: MAX_CONCURRENT,
  };
}

// ── Compute Loop ─────────────────────────────────────────────────────────

function startComputeLoop() {
  running = true;
  self.postMessage({ type: 'status', data: getStatus() });
  scheduleNextPoll(100); // Start almost immediately
}

function stopComputeLoop() {
  running = false;
  if (loopHandle) {
    clearTimeout(loopHandle);
    loopHandle = null;
  }
  self.postMessage({ type: 'status', data: getStatus() });
}

function scheduleNextPoll(delayMs) {
  if (!running) return;
  if (loopHandle) clearTimeout(loopHandle);
  loopHandle = setTimeout(pollAndProcess, delayMs);
}

async function pollAndProcess() {
  if (!running) return;

  try {
    // Check battery status -- reduce work if on battery
    const pollDelay = await getSmartPollDelay();

    // Fetch work package
    const pkg = await fetchWorkPackage();

    if (!pkg || !pkg.jobs || pkg.jobs.length === 0) {
      self.postMessage({ type: 'idle', data: { nextPollMs: pollDelay } });
      scheduleNextPoll(pollDelay);
      return;
    }

    // Process each job sequentially (avoid thrashing the main thread)
    for (const job of pkg.jobs) {
      if (!running) break;
      await processJob(job);
    }

    // Update stats to frontend
    self.postMessage({ type: 'status', data: getStatus() });

    // Schedule next poll -- use server-recommended interval or default
    const nextPoll = pkg.poll_interval_ms || BASE_POLL_MS;
    scheduleNextPoll(Math.max(nextPoll, pollDelay));

  } catch (err) {
    self.postMessage({ type: 'error', data: { message: err.message || 'Poll failed' } });
    // Back off on error
    scheduleNextPoll(IDLE_POLL_MS);
  }
}

// ── Battery-Aware Polling ────────────────────────────────────────────────

async function getSmartPollDelay() {
  try {
    if (typeof navigator !== 'undefined' && navigator.getBattery) {
      const battery = await navigator.getBattery();
      if (!battery.charging && battery.level < 0.3) {
        return BATTERY_POLL_MS * 2; // Very low battery -- minimal work
      }
      if (!battery.charging) {
        return BATTERY_POLL_MS; // On battery -- reduce frequency
      }
    }
  } catch {
    // getBattery not supported -- use default
  }
  return BASE_POLL_MS;
}

// ── API Calls ────────────────────────────────────────────────────────────

async function fetchWorkPackage() {
  const res = await fetch(`${apiBase}/compute/client/work-package?limit=${MAX_CONCURRENT}`, {
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
  });

  if (res.status === 401) {
    // Token expired -- stop the worker
    stopComputeLoop();
    self.postMessage({ type: 'error', data: { message: 'Authentication expired' } });
    return null;
  }

  if (!res.ok) {
    return null;
  }

  return await res.json();
}

async function submitResult(jobId, result, cpuTimeMs) {
  const deviceInfo = [
    typeof navigator !== 'undefined' ? navigator.userAgent : 'worker',
    `cores:${(typeof navigator !== 'undefined' && navigator.hardwareConcurrency) || '?'}`,
    typeof navigator !== 'undefined' && navigator.gpu ? 'gpu:yes' : 'gpu:no',
  ].join(' | ');

  const res = await fetch(`${apiBase}/compute/client/jobs/${jobId}/result`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      result,
      device_info: deviceInfo,
      cpu_time_ms: cpuTimeMs,
    }),
  });

  return res.ok;
}

async function reportFailure(jobId, errorMessage) {
  await fetch(`${apiBase}/compute/client/jobs/${jobId}/fail`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ error_message: errorMessage }),
  }).catch(() => {});
}

// ── Job Processing ───────────────────────────────────────────────────────

async function processJob(job) {
  const startTime = performance.now();

  try {
    let result;

    switch (job.job_type) {
      case 'backtest':
        result = runBacktestSimulation(job.payload);
        break;
      case 'signal_analysis':
        result = scoreSignals(job.payload);
        break;
      case 'strategy_score':
        result = computeStrategyScore(job.payload);
        break;
      case 'walk_forward':
        result = walkForwardValidation(job.payload);
        break;
      case 'strategy_metrics':
        result = computeStrategyMetrics(job.payload);
        break;
      default:
        throw new Error(`Unknown job type: ${job.job_type}`);
    }

    const cpuTimeMs = performance.now() - startTime;
    const submitted = await submitResult(job.id, result, cpuTimeMs);

    if (submitted) {
      jobsCompleted++;
      totalCpuTimeMs += cpuTimeMs;
      lastJobAt = new Date().toISOString();
      self.postMessage({
        type: 'job_completed',
        data: { jobId: job.id, jobType: job.job_type, cpuTimeMs: Math.round(cpuTimeMs) },
      });
    }

  } catch (err) {
    jobsFailed++;
    const errMsg = err.message || 'Processing error';
    await reportFailure(job.id, errMsg);
    self.postMessage({
      type: 'job_failed',
      data: { jobId: job.id, error: errMsg },
    });
  }
}

// ═════════════════════════════════════════════════════════════════════════
// COMPUTATION FUNCTIONS — Pure JavaScript, no server dependencies
// ═════════════════════════════════════════════════════════════════════════

/**
 * Run a backtest simulation on OHLCV data with signal entries.
 *
 * @param {Object} payload - { signals, ohlcv, initial_capital, commission_pct }
 *   signals: [{ bar_index, direction, confidence, strategy }]
 *   ohlcv: [{ open, high, low, close, volume, timestamp }]
 * @returns {Object} Backtest results
 */
function runBacktestSimulation(payload) {
  const {
    signals = [],
    ohlcv = [],
    initial_capital = 100000,
    commission_pct = 0.001,
    stop_loss_pct = 0.02,
    take_profit_pct = 0.04,
  } = payload;

  if (!ohlcv.length) {
    return { trades: [], metrics: { total_return: 0, sharpe: 0, win_rate: 0, trade_count: 0 } };
  }

  let capital = initial_capital;
  const trades = [];
  const equityCurve = [initial_capital];

  for (const signal of signals) {
    const entryIdx = signal.bar_index;
    if (entryIdx < 0 || entryIdx >= ohlcv.length) continue;

    const entryBar = ohlcv[entryIdx];
    const entryPrice = entryBar.close;
    const direction = signal.direction === 'short' ? -1 : 1;
    const positionSize = Math.floor((capital * 0.02) / (entryPrice * stop_loss_pct));
    if (positionSize <= 0) continue;

    const stopPrice = entryPrice * (1 - direction * stop_loss_pct);
    const targetPrice = entryPrice * (1 + direction * take_profit_pct);

    let exitPrice = null;
    let exitIdx = null;
    let exitReason = 'end_of_data';

    // Walk forward from entry to find exit
    for (let i = entryIdx + 1; i < ohlcv.length; i++) {
      const bar = ohlcv[i];

      // Check stop loss
      if (direction === 1 && bar.low <= stopPrice) {
        exitPrice = stopPrice;
        exitIdx = i;
        exitReason = 'stop_loss';
        break;
      }
      if (direction === -1 && bar.high >= stopPrice) {
        exitPrice = stopPrice;
        exitIdx = i;
        exitReason = 'stop_loss';
        break;
      }

      // Check take profit
      if (direction === 1 && bar.high >= targetPrice) {
        exitPrice = targetPrice;
        exitIdx = i;
        exitReason = 'take_profit';
        break;
      }
      if (direction === -1 && bar.low <= targetPrice) {
        exitPrice = targetPrice;
        exitIdx = i;
        exitReason = 'take_profit';
        break;
      }

      // Time-based exit: max 20 bars
      if (i - entryIdx >= 20) {
        exitPrice = bar.close;
        exitIdx = i;
        exitReason = 'time_exit';
        break;
      }
    }

    if (exitPrice === null) {
      exitPrice = ohlcv[ohlcv.length - 1].close;
      exitIdx = ohlcv.length - 1;
    }

    const grossPnl = direction * (exitPrice - entryPrice) * positionSize;
    const commission = entryPrice * positionSize * commission_pct * 2; // entry + exit
    const netPnl = grossPnl - commission;
    capital += netPnl;
    equityCurve.push(capital);

    trades.push({
      entry_price: round4(entryPrice),
      exit_price: round4(exitPrice),
      direction: direction === 1 ? 'long' : 'short',
      size: positionSize,
      pnl: round2(netPnl),
      pnl_pct: round4((netPnl / (entryPrice * positionSize)) * 100),
      exit_reason: exitReason,
      bars_held: exitIdx - entryIdx,
      strategy: signal.strategy || 'unknown',
      confidence: signal.confidence || 0,
    });
  }

  // Compute metrics
  const wins = trades.filter(t => t.pnl > 0);
  const losses = trades.filter(t => t.pnl <= 0);
  const totalReturn = capital - initial_capital;
  const totalReturnPct = (totalReturn / initial_capital) * 100;

  // Sharpe ratio (annualized, assuming daily returns)
  const returns = [];
  for (let i = 1; i < equityCurve.length; i++) {
    returns.push((equityCurve[i] - equityCurve[i - 1]) / equityCurve[i - 1]);
  }
  const avgReturn = returns.length > 0 ? returns.reduce((a, b) => a + b, 0) / returns.length : 0;
  const stdReturn = returns.length > 1 ? Math.sqrt(returns.reduce((s, r) => s + (r - avgReturn) ** 2, 0) / (returns.length - 1)) : 0;
  const sharpe = stdReturn > 0 ? (avgReturn / stdReturn) * Math.sqrt(252) : 0;

  // Max drawdown
  let peak = initial_capital;
  let maxDrawdown = 0;
  for (const eq of equityCurve) {
    if (eq > peak) peak = eq;
    const dd = (peak - eq) / peak;
    if (dd > maxDrawdown) maxDrawdown = dd;
  }

  // Profit factor
  const grossProfit = wins.reduce((s, t) => s + t.pnl, 0);
  const grossLoss = Math.abs(losses.reduce((s, t) => s + t.pnl, 0));
  const profitFactor = grossLoss > 0 ? grossProfit / grossLoss : grossProfit > 0 ? Infinity : 0;

  return {
    trades,
    metrics: {
      total_return: round2(totalReturn),
      total_return_pct: round2(totalReturnPct),
      sharpe: round4(sharpe),
      win_rate: trades.length > 0 ? round2((wins.length / trades.length) * 100) : 0,
      trade_count: trades.length,
      wins: wins.length,
      losses: losses.length,
      avg_win: wins.length > 0 ? round2(wins.reduce((s, t) => s + t.pnl, 0) / wins.length) : 0,
      avg_loss: losses.length > 0 ? round2(losses.reduce((s, t) => s + t.pnl, 0) / losses.length) : 0,
      profit_factor: round2(profitFactor),
      max_drawdown_pct: round2(maxDrawdown * 100),
      avg_bars_held: trades.length > 0 ? round1(trades.reduce((s, t) => s + t.bars_held, 0) / trades.length) : 0,
      final_capital: round2(capital),
    },
  };
}

/**
 * Score signals based on weights and technical indicators.
 *
 * @param {Object} payload - { signals, weights, lookback_bars }
 *   signals: [{ symbol, strategy, confidence, volume_ratio, rsi, macd_hist }]
 *   weights: { confidence, volume, rsi, macd } (optional, defaults provided)
 * @returns {Object} Scored signals
 */
function scoreSignals(payload) {
  const {
    signals = [],
    weights = {},
    lookback_bars = 200,
  } = payload;

  const w = {
    confidence: weights.confidence || 0.35,
    volume: weights.volume || 0.20,
    rsi: weights.rsi || 0.25,
    macd: weights.macd || 0.20,
  };

  // Normalize weights
  const wSum = w.confidence + w.volume + w.rsi + w.macd;
  w.confidence /= wSum;
  w.volume /= wSum;
  w.rsi /= wSum;
  w.macd /= wSum;

  const scored = signals.map(sig => {
    // Confidence score: direct pass-through (0-1)
    const confScore = clamp(sig.confidence || 0.5, 0, 1);

    // Volume score: volume_ratio > 1.5 is strong, > 3 is extreme
    const volRatio = sig.volume_ratio || 1.0;
    const volScore = clamp(Math.log2(Math.max(volRatio, 0.1)) / 2.5, 0, 1);

    // RSI score: 30-70 is neutral, <30 oversold (buy signal), >70 overbought (sell signal)
    const rsi = sig.rsi || 50;
    const isLong = (sig.direction || 'long') === 'long';
    let rsiScore;
    if (isLong) {
      rsiScore = rsi < 30 ? 1.0 : rsi < 40 ? 0.8 : rsi < 50 ? 0.6 : rsi < 60 ? 0.4 : rsi < 70 ? 0.2 : 0.0;
    } else {
      rsiScore = rsi > 70 ? 1.0 : rsi > 60 ? 0.8 : rsi > 50 ? 0.6 : rsi > 40 ? 0.4 : rsi > 30 ? 0.2 : 0.0;
    }

    // MACD histogram score: positive for longs, negative for shorts
    const macdHist = sig.macd_hist || 0;
    const macdMag = Math.abs(macdHist);
    const macdDir = isLong ? (macdHist > 0 ? 1 : -0.5) : (macdHist < 0 ? 1 : -0.5);
    const macdScore = clamp((macdMag * macdDir) / 2 + 0.5, 0, 1);

    const composite = w.confidence * confScore
                    + w.volume * volScore
                    + w.rsi * rsiScore
                    + w.macd * macdScore;

    return {
      ...sig,
      scores: {
        confidence: round4(confScore),
        volume: round4(volScore),
        rsi: round4(rsiScore),
        macd: round4(macdScore),
        composite: round4(composite),
      },
      composite_score: round4(composite),
      grade: composite >= 0.8 ? 'A' : composite >= 0.65 ? 'B' : composite >= 0.5 ? 'C' : 'D',
    };
  });

  // Sort by composite score descending
  scored.sort((a, b) => b.composite_score - a.composite_score);

  return {
    signals: scored,
    count: scored.length,
    avg_score: scored.length > 0
      ? round4(scored.reduce((s, x) => s + x.composite_score, 0) / scored.length)
      : 0,
    grade_distribution: {
      A: scored.filter(s => s.grade === 'A').length,
      B: scored.filter(s => s.grade === 'B').length,
      C: scored.filter(s => s.grade === 'C').length,
      D: scored.filter(s => s.grade === 'D').length,
    },
    weights_used: w,
  };
}

/**
 * Compute a strategy score for a symbol across all strategy patterns.
 *
 * @param {Object} payload - { symbol, ohlcv, strategies }
 * @returns {Object} Strategy scores
 */
function computeStrategyScore(payload) {
  const { symbol = '', ohlcv = [], strategies = [] } = payload;

  if (!ohlcv.length) {
    return { symbol, scores: [], best_strategy: null };
  }

  // Compute basic technical indicators from OHLCV
  const closes = ohlcv.map(b => b.close);
  const volumes = ohlcv.map(b => b.volume || 0);
  const highs = ohlcv.map(b => b.high);
  const lows = ohlcv.map(b => b.low);

  const sma20 = sma(closes, 20);
  const sma50 = sma(closes, 50);
  const rsiValues = computeRSI(closes, 14);
  const avgVolume = volumes.length > 20 ? volumes.slice(-20).reduce((a, b) => a + b, 0) / 20 : 0;
  const currentVol = volumes.length > 0 ? volumes[volumes.length - 1] : 0;
  const volRatio = avgVolume > 0 ? currentVol / avgVolume : 1;

  const latestClose = closes[closes.length - 1];
  const latestSma20 = sma20.length > 0 ? sma20[sma20.length - 1] : latestClose;
  const latestSma50 = sma50.length > 0 ? sma50[sma50.length - 1] : latestClose;
  const latestRsi = rsiValues.length > 0 ? rsiValues[rsiValues.length - 1] : 50;

  // ATR for volatility
  const atrValues = computeATR(highs, lows, closes, 14);
  const latestAtr = atrValues.length > 0 ? atrValues[atrValues.length - 1] : 0;
  const atrPct = latestClose > 0 ? (latestAtr / latestClose) * 100 : 0;

  // Score each strategy pattern
  const scores = [];

  // Momentum / Breakout strategies favor: SMA crossover, high volume, RSI 50-70
  scores.push({
    strategy: 'Breakout',
    score: round4(scorePattern(latestClose > latestSma20 && latestSma20 > latestSma50 ? 0.8 : 0.2, volRatio, latestRsi, 'long')),
    direction: 'long',
  });

  // Pullback strategies favor: price near SMA20 but above SMA50, RSI 35-50
  scores.push({
    strategy: 'Bullish Pullback',
    score: round4(scorePattern(
      (latestClose > latestSma50 && Math.abs(latestClose - latestSma20) / latestClose < 0.02) ? 0.9 : 0.3,
      volRatio, latestRsi, 'long'
    )),
    direction: 'long',
  });

  // Reversal strategies favor: RSI < 30, high volume, price below SMA20
  scores.push({
    strategy: 'Snap Back Long',
    score: round4(scorePattern(latestRsi < 30 ? 0.9 : latestRsi < 40 ? 0.5 : 0.1, volRatio, latestRsi, 'long')),
    direction: 'long',
  });

  // Short strategies favor: price below SMAs, high volume, RSI > 70
  scores.push({
    strategy: 'Topping Formation',
    score: round4(scorePattern(latestClose < latestSma20 && latestClose < latestSma50 ? 0.8 : 0.2, volRatio, latestRsi, 'short')),
    direction: 'short',
  });

  // Volume strategies
  scores.push({
    strategy: 'Staggering Volume',
    score: round4(clamp(volRatio / 4, 0, 1)),
    direction: volRatio > 2 && latestClose > latestSma20 ? 'long' : 'short',
  });

  // Add any custom strategies from payload
  for (const strat of strategies) {
    scores.push({
      strategy: strat.name || 'Custom',
      score: round4(scorePattern(strat.base_score || 0.5, volRatio, latestRsi, strat.direction || 'long')),
      direction: strat.direction || 'long',
    });
  }

  scores.sort((a, b) => b.score - a.score);

  return {
    symbol,
    scores,
    best_strategy: scores.length > 0 ? scores[0] : null,
    technicals: {
      close: round4(latestClose),
      sma20: round4(latestSma20),
      sma50: round4(latestSma50),
      rsi: round2(latestRsi),
      volume_ratio: round2(volRatio),
      atr_pct: round2(atrPct),
    },
    bar_count: ohlcv.length,
  };
}

/**
 * Walk-forward validation: split data into in-sample and out-of-sample,
 * train on in-sample, validate on out-of-sample.
 *
 * @param {Object} payload - { ohlcv, signals, split_ratio, folds }
 * @returns {Object} Walk-forward results per fold
 */
function walkForwardValidation(payload) {
  const {
    ohlcv = [],
    signals = [],
    split_ratio = 0.7,
    folds = 3,
  } = payload;

  if (ohlcv.length < 50 || signals.length < 5) {
    return { folds: [], summary: { avg_sharpe: 0, stability: 0, is_robust: false } };
  }

  const foldSize = Math.floor(ohlcv.length / folds);
  const results = [];

  for (let f = 0; f < folds; f++) {
    const foldStart = f * foldSize;
    const foldEnd = Math.min(foldStart + foldSize, ohlcv.length);
    const foldData = ohlcv.slice(foldStart, foldEnd);
    const splitIdx = Math.floor(foldData.length * split_ratio);

    const inSample = foldData.slice(0, splitIdx);
    const outSample = foldData.slice(splitIdx);

    // Filter signals to this fold's range
    const foldSignals = signals.filter(
      s => s.bar_index >= foldStart && s.bar_index < foldEnd
    ).map(s => ({ ...s, bar_index: s.bar_index - foldStart }));

    const inSampleSignals = foldSignals.filter(s => s.bar_index < splitIdx);
    const outSampleSignals = foldSignals.filter(s => s.bar_index >= splitIdx).map(
      s => ({ ...s, bar_index: s.bar_index - splitIdx })
    );

    // Run backtest on both samples
    const inResult = runBacktestSimulation({ ohlcv: inSample, signals: inSampleSignals });
    const outResult = runBacktestSimulation({ ohlcv: outSample, signals: outSampleSignals });

    results.push({
      fold: f + 1,
      in_sample: {
        bars: inSample.length,
        trades: inResult.metrics.trade_count,
        sharpe: inResult.metrics.sharpe,
        win_rate: inResult.metrics.win_rate,
        return_pct: inResult.metrics.total_return_pct,
      },
      out_sample: {
        bars: outSample.length,
        trades: outResult.metrics.trade_count,
        sharpe: outResult.metrics.sharpe,
        win_rate: outResult.metrics.win_rate,
        return_pct: outResult.metrics.total_return_pct,
      },
      degradation: inResult.metrics.sharpe > 0
        ? round4(1 - outResult.metrics.sharpe / inResult.metrics.sharpe)
        : 0,
    });
  }

  // Summary
  const outSharpes = results.map(r => r.out_sample.sharpe);
  const avgSharpe = outSharpes.length > 0
    ? outSharpes.reduce((a, b) => a + b, 0) / outSharpes.length
    : 0;
  const sharpeMean = avgSharpe;
  const sharpeStd = outSharpes.length > 1
    ? Math.sqrt(outSharpes.reduce((s, x) => s + (x - sharpeMean) ** 2, 0) / (outSharpes.length - 1))
    : 0;
  const stability = sharpeStd > 0 ? sharpeMean / sharpeStd : (sharpeMean > 0 ? 10 : 0);
  const avgDegradation = results.length > 0
    ? results.reduce((s, r) => s + r.degradation, 0) / results.length
    : 0;

  return {
    folds: results,
    summary: {
      avg_sharpe: round4(avgSharpe),
      sharpe_std: round4(sharpeStd),
      stability: round4(stability),
      avg_degradation: round4(avgDegradation),
      is_robust: avgSharpe > 0.5 && avgDegradation < 0.4 && stability > 1.0,
      fold_count: folds,
    },
  };
}

/**
 * Compute strategy performance metrics from a list of trades.
 *
 * @param {Object} payload - { trades, symbol }
 *   trades: [{ pnl, pnl_pct, bars_held, direction, strategy }]
 * @returns {Object} Aggregated metrics
 */
function computeStrategyMetrics(payload) {
  const { trades = [], symbol = '' } = payload;

  if (!trades.length) {
    return {
      symbol,
      metrics: { trade_count: 0, win_rate: 0, profit_factor: 0, sharpe: 0, avg_pnl: 0 },
      by_strategy: {},
    };
  }

  const byStrategy = {};

  for (const t of trades) {
    const strat = t.strategy || 'unknown';
    if (!byStrategy[strat]) {
      byStrategy[strat] = { wins: 0, losses: 0, total_pnl: 0, pnls: [], bars: [] };
    }
    const bucket = byStrategy[strat];
    const pnl = t.pnl || 0;
    if (pnl > 0) bucket.wins++;
    else bucket.losses++;
    bucket.total_pnl += pnl;
    bucket.pnls.push(pnl);
    bucket.bars.push(t.bars_held || 0);
  }

  // Compute per-strategy metrics
  const strategyMetrics = {};
  for (const [strat, data] of Object.entries(byStrategy)) {
    const count = data.wins + data.losses;
    const grossWins = data.pnls.filter(p => p > 0).reduce((s, p) => s + p, 0);
    const grossLosses = Math.abs(data.pnls.filter(p => p <= 0).reduce((s, p) => s + p, 0));
    const avgPnl = count > 0 ? data.total_pnl / count : 0;
    const meanReturn = avgPnl;
    const stdReturn = count > 1
      ? Math.sqrt(data.pnls.reduce((s, p) => s + (p - meanReturn) ** 2, 0) / (count - 1))
      : 0;

    strategyMetrics[strat] = {
      trade_count: count,
      wins: data.wins,
      losses: data.losses,
      win_rate: count > 0 ? round2((data.wins / count) * 100) : 0,
      total_pnl: round2(data.total_pnl),
      avg_pnl: round2(avgPnl),
      profit_factor: grossLosses > 0 ? round2(grossWins / grossLosses) : (grossWins > 0 ? Infinity : 0),
      sharpe: stdReturn > 0 ? round4((meanReturn / stdReturn) * Math.sqrt(252)) : 0,
      avg_bars_held: count > 0 ? round1(data.bars.reduce((a, b) => a + b, 0) / count) : 0,
    };
  }

  // Aggregate metrics
  const allPnls = trades.map(t => t.pnl || 0);
  const totalPnl = allPnls.reduce((a, b) => a + b, 0);
  const wins = allPnls.filter(p => p > 0);
  const losses = allPnls.filter(p => p <= 0);
  const grossWins = wins.reduce((a, b) => a + b, 0);
  const grossLosses = Math.abs(losses.reduce((a, b) => a + b, 0));
  const avgPnl = allPnls.length > 0 ? totalPnl / allPnls.length : 0;
  const stdPnl = allPnls.length > 1
    ? Math.sqrt(allPnls.reduce((s, p) => s + (p - avgPnl) ** 2, 0) / (allPnls.length - 1))
    : 0;

  return {
    symbol,
    metrics: {
      trade_count: trades.length,
      wins: wins.length,
      losses: losses.length,
      win_rate: round2((wins.length / trades.length) * 100),
      total_pnl: round2(totalPnl),
      avg_pnl: round2(avgPnl),
      profit_factor: grossLosses > 0 ? round2(grossWins / grossLosses) : (grossWins > 0 ? Infinity : 0),
      sharpe: stdPnl > 0 ? round4((avgPnl / stdPnl) * Math.sqrt(252)) : 0,
    },
    by_strategy: strategyMetrics,
    strategy_count: Object.keys(strategyMetrics).length,
    best_strategy: Object.entries(strategyMetrics).sort(
      (a, b) => b[1].sharpe - a[1].sharpe
    )[0]?.[0] || null,
  };
}

