// HELPER FUNCTIONS — Technical indicators & math
// ═════════════════════════════════════════════════════════════════════════

function sma(data, period) {
  if (data.length < period) return [];
  const result = [];
  let sum = 0;
  for (let i = 0; i < period; i++) sum += data[i];
  result.push(sum / period);
  for (let i = period; i < data.length; i++) {
    sum += data[i] - data[i - period];
    result.push(sum / period);
  }
  return result;
}

function computeRSI(closes, period) {
  if (closes.length < period + 1) return [];
  const gains = [];
  const losses = [];
  for (let i = 1; i < closes.length; i++) {
    const diff = closes[i] - closes[i - 1];
    gains.push(diff > 0 ? diff : 0);
    losses.push(diff < 0 ? -diff : 0);
  }

  let avgGain = gains.slice(0, period).reduce((a, b) => a + b, 0) / period;
  let avgLoss = losses.slice(0, period).reduce((a, b) => a + b, 0) / period;

  const result = [];
  const rs = avgLoss > 0 ? avgGain / avgLoss : 100;
  result.push(100 - 100 / (1 + rs));

  for (let i = period; i < gains.length; i++) {
    avgGain = (avgGain * (period - 1) + gains[i]) / period;
    avgLoss = (avgLoss * (period - 1) + losses[i]) / period;
    const rs2 = avgLoss > 0 ? avgGain / avgLoss : 100;
    result.push(100 - 100 / (1 + rs2));
  }

  return result;
}

function computeATR(highs, lows, closes, period) {
  if (highs.length < period + 1) return [];
  const trs = [];
  for (let i = 1; i < highs.length; i++) {
    const tr = Math.max(
      highs[i] - lows[i],
      Math.abs(highs[i] - closes[i - 1]),
      Math.abs(lows[i] - closes[i - 1])
    );
    trs.push(tr);
  }
  // Simple ATR: SMA of true ranges
  return sma(trs, period);
}

function scorePattern(baseScore, volRatio, rsi, direction) {
  // Combine base pattern score with volume and RSI confirmation
  const volBoost = clamp((volRatio - 1) * 0.2, -0.2, 0.3);
  let rsiBoost = 0;
  if (direction === 'long') {
    rsiBoost = rsi < 40 ? 0.15 : rsi > 70 ? -0.1 : 0;
  } else {
    rsiBoost = rsi > 60 ? 0.15 : rsi < 30 ? -0.1 : 0;
  }
  return clamp(baseScore + volBoost + rsiBoost, 0, 1);
}

function clamp(val, min, max) {
  return Math.max(min, Math.min(max, val));
}

function round1(n) { return Math.round(n * 10) / 10; }
function round2(n) { return Math.round(n * 100) / 100; }
function round4(n) { return Math.round(n * 10000) / 10000; }
